import java.util.*; public class RockPaperScissors{public static void main(String[] a){Scanner sc=new Scanner(System.in);String[] op={"rock","paper","scissors"};int n=sc.nextInt(),u=0,c=0;for(int i=0;i<n;i++){String p=sc.next();String pc=op[(int)(Math.random()*3)];if((p.equals("rock")&&pc.equals("scissors"))||(p.equals("paper")&&pc.equals("rock"))||(p.equals("scissors")&&pc.equals("paper")))u++;else if(!p.equals(pc))c++;}System.out.println("User="+u);System.out.println("Computer="+c);}}